#[test]
fn basic_poll_interval_configurable() {
    let _guard = TEST_MUTEX.lock().unwrap();
    // Verify BASIC_POLL_INTERVAL_MS can be set (same code the macro would generate)
    ferris_gc::BASIC_POLL_INTERVAL_MS.store(200, std::sync::atomic::Ordering::Release);
    // Restore default
    ferris_gc::BASIC_POLL_INTERVAL_MS.store(50, std::sync::atomic::Ordering::Release);
}
